@startuml
title Diagrama de Classe - Acompanhamentos

abstract class Acai {
    + String descricao
    + Tamanho tamanho
    + double getPreco()
    + String getDescricao()
    + Tamanho getTamanho()
}

class AcaiNaBarca
class AcaiNaTigela
class AcaiNoCopo
class AcaiNaBarcaComMorango {
    + AcaiNaBarca acaiNaBarca
    + Morango morango
}
class AcaiNaTigelaComMorango {
    + AcaiNaTigela acaiNaTigela
    + Morango morango
}
class AcaiNoCopoComMorango {
    + AcaiNoCopo acaiNoCopo
    + Morango morango
}
class AcaiNaBarcaComMorangoELeiteEmPo {
    + AcaiNaBarca acaiNaBarca
    + Morango morango
    + LeiteEmPo leiteEmPo
}

class Tamanho {
    PEQUENO
    MEDIO
    GRANDE
}

class Morango {
    + double preco
    + double preco
    + double getPreco()
    + double getPreco()
}

class LeiteEmPo {
    + double preco
    + double getPreco()
}

Acai <|-- AcaiNaBarca
Acai <|-- AcaiNaTigela
Acai <|-- AcaiNoCopo
Acai <|-- AcaiNaBarcaComMorango
Acai <|-- AcaiNaTigelaComMorango
Acai <|-- AcaiNoCopoComMorango
Acai <|-- AcaiNaBarcaComMorangoELeiteEmPo

note right of Acai
    Método abstrato que deve ser
    implementado por toda Classe
    que herda de Acai
end note

@enduml
